class Solution:
    def countBinarySubstrings(self, s: str) -> int:
        result = 0
        prev, curr = 0, 1
        for i in range(1, len(s)):
            if s[i-1] != s[i]:
                result += min(prev, curr)
                prev, curr = curr, 1
            else:
                curr += 1
        return result + min(prev, curr)
```
